                <Trophy size={20} /> SET MILESTONE
              </button>
          </div>
      </Modal>
    </div>
  );
}

import React from 'react';
import { Check, Trash2, Flame, Zap, Bell, Calendar, Clock, Repeat } from 'lucide-react';
import { Habit, Category, Frequency } from '../types';

interface HabitTrackerProps {
  habits: Habit[];
  completedHabitIds: string[];
  onToggleHabit: (id: string) => void;
  onDeleteHabit: (id: string) => void;
}

// Move helper to determine colors based on category outside for cleaner code
const getCategoryTheme = (cat: Category) => {
  switch(cat) {
    case Category.HEALTH: return { color: 'text-emerald-600 dark:text-emerald-400', bg: 'bg-emerald-50 dark:bg-emerald-400/10', border: 'border-emerald-100 dark:border-emerald-400/20' };
    case Category.WORK: return { color: 'text-blue-600 dark:text-blue-400', bg: 'bg-blue-50 dark:bg-blue-400/10', border: 'border-blue-100 dark:border-blue-400/20' };
    case Category.LEARNING: return { color: 'text-amber-600 dark:text-amber-400', bg: 'bg-amber-50 dark:bg-amber-400/10', border: 'border-amber-100 dark:border-amber-400/20' };
    case Category.MINDFULNESS: return { color: 'text-purple-600 dark:text-purple-400', bg: 'bg-purple-50 dark:bg-purple-400/10', border: 'border-purple-100 dark:border-purple-400/20' };
    default: return { color: 'text-slate-600 dark:text-slate-400', bg: 'bg-slate-50 dark:bg-slate-400/10', border: 'border-slate-100 dark:border-slate-400/20' };
  }
};

// Define props interface for HabitItem
interface HabitItemProps {
  habit: Habit;
  index: number;
  isCompleted: boolean;
  onToggleHabit: (id: string) => void;
  onDeleteHabit: (id: string) => void;
}

// Fixed: Use React.FC with HabitItemProps to resolve "key" prop errors
const HabitItem: React.FC<HabitItemProps> = ({ 
  habit, 
  index, 
  isCompleted, 
  onToggleHabit, 
  onDeleteHabit 
}) => {
  const theme = getCategoryTheme(habit.category);

  return (
    <div 
      style={{ animationDelay: `${index * 50}ms` }}
      className={`group bg-white dark:bg-slate-900 p-6 rounded-[2rem] border transition-all duration-300 flex flex-col justify-between ${
        isCompleted 
          ? 'opacity-60 border-emerald-200 dark:border-emerald-500/40 shadow-sm' 
          : 'border-slate-200 dark:border-slate-800 hover:border-violet-400 dark:hover:border-violet-600 hover:shadow-xl dark:hover:shadow-none'
      }`}
    >
      <div className="flex justify-between items-start mb-6">
        <div className="flex gap-4 min-w-0">
          <button
            onClick={() => onToggleHabit(habit.id)}
            aria-label={isCompleted ? "Mark habit as incomplete" : "Mark habit as complete"}
            className={`flex-shrink-0 h-14 w-14 rounded-2xl flex items-center justify-center transition-all duration-500 border-2 relative group/btn ${
              isCompleted
                ? 'bg-emerald-500 border-emerald-400 text-white shadow-lg shadow-emerald-200 dark:shadow-none'
                : 'bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700 text-slate-400 dark:text-slate-500 hover:border-violet-400 dark:hover:border-violet-500'
            }`}
          >
            <Check 
              size={28} 
              strokeWidth={4} 
              className={`transition-all duration-500 ${isCompleted ? 'scale-100 opacity-100' : 'scale-50 opacity-0'}`} 
            />
            {!isCompleted && (
              <Check 
                size={28} 
                strokeWidth={4} 
                className="absolute opacity-0 group-hover/btn:opacity-20 transition-opacity text-violet-600 dark:text-violet-400" 
              />
            )}
          </button>

          <div className="min-w-0">
            <div className="flex items-center gap-2 mb-1">
              <h4 className={`font-black text-lg truncate transition-all ${isCompleted ? 'text-slate-400 dark:text-slate-500 line-through' : 'text-slate-900 dark:text-white'}`}>
                {habit.title}
              </h4>
              {habit.streak > 0 && (
                <div className="flex items-center gap-1 px-2 py-0.5 rounded-full bg-orange-100 dark:bg-orange-500/20 text-orange-600 dark:text-orange-400 text-[10px] font-black uppercase tracking-tighter">
                  <Flame size={10} fill="currentColor" />
                  {habit.streak}
                </div>
              )}
            </div>
            <div className="flex items-center gap-2">
              <span className={`text-[10px] font-black uppercase tracking-widest px-2 py-0.5 rounded-md ${theme.bg} ${theme.color} border ${theme.border}`}>
                {habit.category}
              </span>
              {habit.reminderTime && (
                 <span className="text-[10px] font-bold text-slate-400 dark:text-slate-500 flex items-center gap-1">
                  <Clock size={10} /> {habit.reminderTime}
                </span>
              )}
            </div>
          </div>
        </div>

        <button 
          onClick={() => onDeleteHabit(habit.id)}
          className="opacity-0 group-hover:opacity-100 p-2 text-slate-300 dark:text-slate-600 hover:text-rose-500 dark:hover:text-rose-400 transition-all"
        >
          <Trash2 size={16} />
        </button>
      </div>

      <div className="flex items-center justify-between mt-auto">
         <div className="flex gap-1">
            {[...Array(5)].map((_, i) => (
              <div key={i} className={`w-1.5 h-4 rounded-full ${i < (habit.streak % 5 || (habit.streak > 0 ? 5 : 0)) ? 'bg-violet-600 dark:bg-violet-500' : 'bg-slate-100 dark:bg-slate-800'}`}></div>
            ))}
         </div>
         <div className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest flex items-center gap-1">
            {habit.frequency === Frequency.DAILY && <Repeat size={10} />}
            {habit.frequency === Frequency.WEEKLY && <Calendar size={10} />}
            {habit.frequency === Frequency.MONTHLY && <Calendar size={10} />}
            {habit.frequency}
         </div>
      </div>
    </div>
  );
};

export const HabitTracker: React.FC<HabitTrackerProps> = ({ 
  habits, 
  completedHabitIds, 
  onToggleHabit,
  onDeleteHabit
}) => {

  const dailyHabits = habits.filter(h => h.frequency === Frequency.DAILY);
  const weeklyHabits = habits.filter(h => h.frequency === Frequency.WEEKLY);
  const monthlyHabits = habits.filter(h => h.frequency === Frequency.MONTHLY);

  if (habits.length === 0) {
    return (
      <div className="text-center py-20 px-4 bg-white dark:bg-slate-900 rounded-[2rem] border border-dashed border-slate-300 dark:border-slate-700 transition-colors">
        <div className="w-16 h-16 bg-slate-50 dark:bg-slate-800 rounded-2xl flex items-center justify-center mx-auto mb-4">
          <Zap size={28} className="text-slate-400 dark:text-slate-600" />
        </div>
        <h3 className="text-xl font-bold text-slate-800 dark:text-white mb-2">The canvas is empty</h3>
        <p className="text-slate-500 dark:text-slate-400 max-w-xs mx-auto">Start architecting your routines by adding your first habit.</p>
      </div>
    );
  }

  return (
    <div className="space-y-12 pb-12">
      {/* Daily Section */}
      {dailyHabits.length > 0 && (
        <section className="space-y-6">
          <div className="flex items-center gap-3 px-2">
            <div className="w-1 h-6 bg-violet-600 rounded-full"></div>
            <h3 className="font-black text-slate-400 uppercase tracking-widest text-xs">Daily Routines</h3>
            <span className="text-[10px] font-black bg-violet-100 dark:bg-violet-900/30 text-violet-600 dark:text-violet-400 px-2 py-0.5 rounded-md">{dailyHabits.length}</span>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {dailyHabits.map((habit, idx) => (
              <HabitItem 
                key={habit.id} 
                habit={habit} 
                index={idx} 
                isCompleted={completedHabitIds.includes(habit.id)}
                onToggleHabit={onToggleHabit}
                onDeleteHabit={onDeleteHabit}
              />
            ))}
          </div>
        </section>
      )}

      {/* Weekly Section */}
      {weeklyHabits.length > 0 && (
        <section className="space-y-6">
          <div className="flex items-center gap-3 px-2">
            <div className="w-1 h-6 bg-emerald-600 rounded-full"></div>
            <h3 className="font-black text-slate-400 uppercase tracking-widest text-xs">Weekly Architectures</h3>
            <span className="text-[10px] font-black bg-emerald-100 dark:bg-emerald-900/30 text-emerald-600 dark:text-emerald-400 px-2 py-0.5 rounded-md">{weeklyHabits.length}</span>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {weeklyHabits.map((habit, idx) => (
              <HabitItem 
                key={habit.id} 
                habit={habit} 
                index={idx + dailyHabits.length} 
                isCompleted={completedHabitIds.includes(habit.id)}
                onToggleHabit={onToggleHabit}
                onDeleteHabit={onDeleteHabit}
              />
            ))}
          </div>
        </section>
      )}

      {/* Monthly Section */}
      {monthlyHabits.length > 0 && (
        <section className="space-y-6">
          <div className="flex items-center gap-3 px-2">
            <div className="w-1 h-6 bg-amber-600 rounded-full"></div>
            <h3 className="font-black text-slate-400 uppercase tracking-widest text-xs">Monthly Milestones</h3>
            <span className="text-[10px] font-black bg-amber-100 dark:bg-amber-900/30 text-amber-600 dark:text-amber-400 px-2 py-0.5 rounded-md">{monthlyHabits.length}</span>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {monthlyHabits.map((habit, idx) => (
              <HabitItem 
                key={habit.id} 
                habit={habit} 
                index={idx + dailyHabits.length + weeklyHabits.length} 
                isCompleted={completedHabitIds.includes(habit.id)}
                onToggleHabit={onToggleHabit}
                onDeleteHabit={onDeleteHabit}
              />
            ))}
          </div>
        </section>
      )}
    </div>
  );
};

import React, { useState, useEffect, Suspense, lazy, useCallback, useMemo } from 'react';
import { 
  Plus, Layout, CheckCircle2, Target, Menu, Home, ListChecks, 
  LogOut, Moon, Sun, Cloud, BarChart3, Medal, Sparkles,
  Heart, Briefcase, GraduationCap, Compass, HelpCircle, 
  Trophy, Repeat, Calendar
} from 'lucide-react';
import { format } from 'date-fns';
import { supabase, isSupabaseConfigured } from './services/supabaseClient';

import { Habit, Goal, Category, AppState, Frequency, User, DailyLog } from './types';
import { AuthScreen, TEST_ACCOUNT_ID } from './components/AuthScreen';
import { LandingPage } from './components/LandingPage';
import { HabitTracker } from './components/HabitTracker';
import { GoalTracker } from './components/GoalTracker';
import { AIOverview } from './components/AIOverview';
import { Modal } from './components/UIComponents';

// Lazy loaded modules for performance
const Analytics = lazy(() => import('./components/Analytics').then(m => ({ default: m.Analytics })));
const Achievements = lazy(() => import('./components/Achievements').then(m => ({ default: m.Achievements })));
const KairoChat = lazy(() => import('./components/KairoChat').then(m => ({ default: m.KairoChat })));

const getTodayKey = () => format(new Date(), 'yyyy-MM-dd');

export default function App() {
  const [user, setUser] = useState<User | null>(null);
  const [state, setState] = useState<AppState>({ habits: [], goals: [], logs: {}, earnedBadges: [] });
  const [isLoaded, setIsLoaded] = useState(false);
  const [saveStatus, setSaveStatus] = useState<'saved' | 'saving' | 'error'>('saved');
  const [currentPath, setCurrentPath] = useState(window.location.pathname || '/');

  // Sidebar and Modal State
  const [isSidebarOpen, setSidebarOpen] = useState(false); 
  const [isHabitModalOpen, setHabitModalOpen] = useState(false);
  const [isGoalModalOpen, setGoalModalOpen] = useState(false);

  // Form State
  const [newHabitTitle, setNewHabitTitle] = useState('');
  const [newHabitCategory, setNewHabitCategory] = useState<Category>(Category.OTHER);
  const [newHabitFrequency, setNewHabitFrequency] = useState<Frequency>(Frequency.DAILY);
  const [newGoalTitle, setNewGoalTitle] = useState('');
  const [newGoalTarget, setNewGoalTarget] = useState<number>(10);
  const [newGoalUnit, setNewGoalUnit] = useState('Units');
  const [newGoalFrequency, setNewGoalFrequency] = useState<Frequency>(Frequency.ONCE);

  const [isDarkMode, setIsDarkMode] = useState(() => {
    if (typeof window !== 'undefined') {
      return localStorage.getItem('theme') === 'dark' || 
             (!localStorage.getItem('theme') && window.matchMedia('(prefers-color-scheme: dark)').matches);
    }
    return false;
  });

  const navigateTo = (path: string) => {
    window.history.pushState({}, '', path);
    setCurrentPath(path);
    setSidebarOpen(false);
  };

  const loadUserData = useCallback(async (userData: User) => {
    const client = supabase; if (!client) { setIsLoaded(true); return; }
    try {
      const { data, error } = await client.from('user_data').select('content').eq('user_id', userData.id).single();
      if (data?.content) setState(data.content as AppState);
    } catch (err) {
        console.warn("Starting fresh record for architect:", userData.email);
    } finally { setIsLoaded(true); }
  }, []);

  // Sync theme
  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('theme', 'light');
    }
  }, [isDarkMode]);

  // Combined Auth Effect
  useEffect(() => {
    const client = supabase;
    if (!isSupabaseConfigured() || !client) { setIsLoaded(true); return; }

    client.auth.getSession().then(({ data: { session } }) => {
        if (session?.user) {
            const userData: User = {
                id: session.user.id,
                email: session.user.email || '',
                name: session.user.user_metadata?.full_name || 'Architect'
            };
            setUser(userData);
            loadUserData(userData);
            if (window.location.pathname === '/' || window.location.pathname === '/login') navigateTo('/dashboard');
        } else {
            setIsLoaded(true);
        }
    });

    const { data: { subscription } } = client.auth.onAuthStateChange((event, session) => {
        if (event === 'SIGNED_IN' && session?.user) {
            const userData: User = {
                id: session.user.id,
                email: session.user.email || '',
                name: session.user.user_metadata?.full_name || 'Architect'
            };
            setUser(userData);
            loadUserData(userData);
            navigateTo('/dashboard');
        } else if (event === 'SIGNED_OUT') {
            setUser(null);
            setState({ habits: [], goals: [], logs: {}, earnedBadges: [] });
            navigateTo('/');
        }
    });

    return () => subscription.unsubscribe();
  }, [loadUserData]);

  // Achievement Engine - Auto-check and award badges
  useEffect(() => {
    if (!isLoaded || !user) return;

    const todayKey = getTodayKey();
    // Fixed: Explicitly cast todayLog to DailyLog to avoid "unknown" type issues
    const todayLog = (state.logs[todayKey] || { completedHabitIds: [] }) as DailyLog;
    // Fixed: Cast Object.values to DailyLog[] to resolve reduce error on "unknown" property access
    const totalCompletions = (Object.values(state.logs) as DailyLog[]).reduce((acc, log) => acc + log.completedHabitIds.length, 0);
    const hasActiveHabits = state.habits.length > 0;
    const maxStreak = Math.max(0, ...state.habits.map(h => h.streak));
    const hasCompletedGoal = state.goals.some(g => g.current >= g.target);

    const newBadges: string[] = [];
    if (hasActiveHabits) newBadges.push('first_step');
    if (state.habits.length >= 5) newBadges.push('architect');
    if (hasCompletedGoal) newBadges.push('goal_getter');
    if (maxStreak >= 3) newBadges.push('streak_3');
    if (maxStreak >= 7) newBadges.push('streak_7');
    if (maxStreak >= 30) newBadges.push('streak_30');
    // totalCompletions is now inferred as number from the casted reduce
    if (totalCompletions >= 50) newBadges.push('consistent');
    if (hasActiveHabits && todayLog.completedHabitIds.length === state.habits.length) newBadges.push('high_flyer');

    const updatedBadges = [...new Set([...state.earnedBadges, ...newBadges])];

    if (updatedBadges.length !== state.earnedBadges.length) {
      setState(prev => ({ ...prev, earnedBadges: updatedBadges }));
    }
  }, [state.habits, state.goals, state.logs, isLoaded, user]);

  // Auto-Save
  useEffect(() => {
    if (!isLoaded || !user || user.id === TEST_ACCOUNT_ID) return;

    const saveData = async () => {
      setSaveStatus('saving');
      const client = supabase; if (!client) return;
      try {
        const { error } = await client.from('user_data').upsert({ 
            user_id: user.id, 
            content: state, 
            updated_at: new Date().toISOString() 
        }, { onConflict: 'user_id' });

        if (error) throw error;
        setSaveStatus('saved');
      } catch (err) { 
        console.error("Cloud Sync Error:", err);
        setSaveStatus('error'); 
      }
    };
    const timeoutId = setTimeout(saveData, 3000);
    return () => clearTimeout(timeoutId);
  }, [state, isLoaded, user]);

  const handleSignOut = async () => {
    if (user?.id === TEST_ACCOUNT_ID) {
      setUser(null);
      setState({ habits: [], goals: [], logs: {}, earnedBadges: [] });
      navigateTo('/');
    } else {
      await supabase?.auth.signOut();
    }
  };

  const toggleHabit = (id: string) => {
    const todayKey = getTodayKey();
    setState(prev => {
      const currentLog = prev.logs[todayKey] || { date: todayKey, completedHabitIds: [], goalProgress: {} };
      const isCompleted = currentLog.completedHabitIds.includes(id);
      const newCompletedIds = isCompleted 
        ? currentLog.completedHabitIds.filter(hid => hid !== id)
        : [...currentLog.completedHabitIds, id];

      if (!isCompleted && typeof window !== 'undefined' && (window as any).confetti) {
        (window as any).confetti({
          particleCount: 100,
          spread: 70,
          origin: { y: 0.6 },
          colors: ['#7c3aed', '#10b981', '#6366f1']
        });
      }

      // Update streaks logic
      const updatedHabits = prev.habits.map(h => {
        if (h.id === id) {
          return { ...h, streak: !isCompleted ? h.streak + 1 : Math.max(0, h.streak - 1) };
        }
        return h;
      });

      return {
        ...prev,
        habits: updatedHabits,
        logs: { 
          ...prev.logs, 
          [todayKey]: { ...currentLog, completedHabitIds: newCompletedIds } 
        }
      };
    });
  };

  const addHabit = () => {
    if (!newHabitTitle.trim()) return;
    const habitId = typeof crypto !== 'undefined' && crypto.randomUUID ? crypto.randomUUID() : Math.random().toString(36).substring(2, 15);
    const newHabit: Habit = { 
      id: habitId,
      title: newHabitTitle, 
      category: newHabitCategory, 
      createdAt: new Date().toISOString(), 
      streak: 0, 
      frequency: newHabitFrequency 
    };
    setState(prev => ({ ...prev, habits: [...prev.habits, newHabit] }));
    setNewHabitTitle(''); 
    setHabitModalOpen(false);
  };

  const addGoal = () => {
    if (!newGoalTitle.trim()) return;
    const goalId = typeof crypto !== 'undefined' && crypto.randomUUID ? crypto.randomUUID() : Math.random().toString(36).substring(2, 15);
    const newGoal: Goal = {
      id: goalId,
      title: newGoalTitle,
      target: newGoalTarget,
      current: 0,
      unit: newGoalUnit,
      frequency: newGoalFrequency
    };
    setState(prev => ({ ...prev, goals: [...prev.goals, newGoal] }));
    setNewGoalTitle('');
    setGoalModalOpen(false);
  };

  const renderContent = () => {
    const todayKey = getTodayKey();
    const todayLog = state.logs[todayKey] || { date: todayKey, completedHabitIds: [], goalProgress: {} };
    const percentage = state.habits.length > 0 ? Math.round((todayLog.completedHabitIds.length / state.habits.length) * 100) : 0;

    switch(currentPath) {
      case '/routines':
        return (
          <div className="space-y-8 animate-in fade-in duration-500">
            <div className="flex justify-between items-center mb-4">
                <h2 className="text-3xl font-black text-slate-900 dark:text-white uppercase tracking-tighter">Your Routines</h2>
                <button onClick={() => setHabitModalOpen(true)} className="bg-violet-600 text-white px-6 py-3 rounded-xl font-bold flex items-center gap-2 shadow-lg shadow-violet-200 dark:shadow-none"><Plus size={20}/> New</button>
            </div>
            <HabitTracker habits={state.habits} completedHabitIds={todayLog.completedHabitIds} onToggleHabit={toggleHabit} onDeleteHabit={(id) => setState(prev => ({ ...prev, habits: prev.habits.filter(h => h.id !== id) }))} />
          </div>
        );
      case '/milestones':
        return (
          <div className="space-y-8 animate-in fade-in duration-500">
            <div className="flex justify-between items-center mb-4">
                <h2 className="text-3xl font-black text-slate-900 dark:text-white uppercase tracking-tighter">Milestones</h2>
                <button onClick={() => setGoalModalOpen(true)} className="bg-emerald-600 text-white px-6 py-3 rounded-xl font-bold flex items-center gap-2 shadow-lg shadow-emerald-200 dark:shadow-none"><Plus size={20}/> New Milestone</button>
            </div>
            <GoalTracker goals={state.goals} onUpdateProgress={(id, delta) => setState(prev => ({ ...prev, goals: prev.goals.map(g => g.id === id ? { ...g, current: Math.max(0, g.current + delta) } : g) }))} onDeleteGoal={(id) => setState(prev => ({ ...prev, goals: prev.goals.filter(g => g.id !== id) }))} />
          </div>
        );
      case '/insights':
        return (
          <Suspense fallback={<div className="h-64 flex items-center justify-center animate-pulse bg-slate-100 dark:bg-slate-800 rounded-3xl" />}>
            <Analytics habits={state.habits} goals={state.goals} logs={state.logs} />
          </Suspense>
        );
      case '/trophies':
        return (
          <Suspense fallback={null}>
            <div className="space-y-12 animate-in fade-in duration-500">
               <h2 className="text-3xl font-black text-slate-900 dark:text-white uppercase tracking-tighter">Trophy Room</h2>
               <Achievements earnedBadgeIds={state.earnedBadges} />
            </div>
          </Suspense>
        );
      default: // Dashboard
        return (
          <div className="space-y-12 animate-in fade-in duration-500">
            <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-6">
              <h2 className="text-4xl md:text-5xl font-black text-slate-900 dark:text-white tracking-tight leading-none">Design your <br /><span className="text-violet-600">Success.</span></h2>
              <div className="flex gap-4">
                <button onClick={() => setHabitModalOpen(true)} className="bg-slate-900 dark:bg-white text-white dark:text-slate-900 px-6 py-4 rounded-2xl font-black shadow-xl hover:scale-105 transition-all flex items-center justify-center gap-3"><Plus size={20} /> New Routine</button>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div className="bg-white dark:bg-slate-900 p-8 rounded-3xl border border-slate-200 dark:border-slate-800 flex flex-col gap-4 shadow-sm transition-colors group">
                <CheckCircle2 className="text-emerald-500 group-hover:scale-110 transition-transform" size={32} />
                <span className="text-4xl font-black dark:text-white">{percentage}%</span>
                <p className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Daily Trajectory</p>
              </div>
            </div>

            <div className="grid grid-cols-1 xl:grid-cols-3 gap-10">
              <div className="xl:col-span-2 space-y-8">
                <AIOverview habits={state.habits} goals={state.goals} logs={state.logs} />
                <section id="habits-list" className="space-y-6">
                   <div className="flex items-center gap-2">
                     <ListChecks size={20} className="text-slate-400" />
                     <h3 className="font-black text-slate-400 uppercase tracking-widest text-xs">Structural Blueprint</h3>
                   </div>
                  <HabitTracker habits={state.habits} completedHabitIds={todayLog.completedHabitIds} onToggleHabit={toggleHabit} onDeleteHabit={(id) => setState(prev => ({ ...prev, habits: prev.habits.filter(h => h.id !== id) }))} />
                </section>
              </div>
              <div className="xl:col-span-1">
                 <div className="flex items-center justify-between mb-6">
                    <div className="flex items-center gap-2">
                        <Target size={20} className="text-slate-400" />
                        <h3 className="font-black text-slate-400 uppercase tracking-widest text-xs">Milestones</h3>
                    </div>
                 </div>
                <GoalTracker goals={state.goals} onUpdateProgress={(id, delta) => setState(prev => ({ ...prev, goals: prev.goals.map(g => g.id === id ? { ...g, current: Math.max(0, g.current + delta) } : g) }))} onDeleteGoal={(id) => setState(prev => ({ ...prev, goals: prev.goals.filter(g => g.id !== id) }))} />
              </div>
            </div>
          </div>
        );
    }
  };

  const categories = [
    { type: Category.HEALTH, icon: Heart },
    { type: Category.WORK, icon: Briefcase },
    { type: Category.LEARNING, icon: GraduationCap },
    { type: Category.MINDFULNESS, icon: Compass },
    { type: Category.OTHER, icon: HelpCircle }
  ];

  const frequencies = [
    { type: Frequency.DAILY, label: 'Daily' },
    { type: Frequency.WEEKLY, label: 'Weekly' },
    { type: Frequency.MONTHLY, label: 'Monthly' },
    { type: Frequency.ONCE, label: 'One-time' }
  ];

  if (!isLoaded) return <div className="min-h-screen flex items-center justify-center bg-slate-50 dark:bg-slate-950 transition-colors"><div className="w-12 h-12 border-4 border-t-violet-600 rounded-full animate-spin"></div></div>;
  if (!user && currentPath === '/login') return <AuthScreen onAuthSuccess={(u) => { setUser(u); navigateTo('/dashboard'); }} />;
  if (!user) return <LandingPage onStart={() => navigateTo('/login')} />;

  return (
    <div id="root-container" className="flex h-screen bg-slate-50 dark:bg-slate-950 transition-colors overflow-hidden">
      {isSidebarOpen && <div className="fixed inset-0 bg-black/50 z-40 lg:hidden" onClick={() => setSidebarOpen(false)} />}

      <aside className={`fixed inset-y-0 left-0 z-50 w-72 bg-white dark:bg-slate-900 border-r border-slate-200 dark:border-slate-800 transform lg:relative lg:translate-x-0 transition-transform duration-300 ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}`}>
        <div className="flex flex-col h-full p-8">
          <div className="flex items-center gap-4 mb-12">
            <div className="bg-violet-600 p-2.5 rounded-xl shadow-lg"><Layout className="text-white" size={24} /></div>
            <h1 className="text-2xl font-black text-slate-900 dark:text-white uppercase tracking-tighter">Habit<span className="text-violet-500">Arch</span></h1>
          </div>
          <nav className="space-y-2 flex-1">
             <button onClick={() => navigateTo('/dashboard')} className={`w-full flex items-center gap-4 px-5 py-4 rounded-xl font-bold transition-all ${currentPath === '/dashboard' || currentPath === '/' ? 'bg-violet-600 text-white shadow-xl' : 'text-slate-500 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800'}`}><Home size={20} /> Vision</button>
             <button onClick={() => navigateTo('/routines')} className={`w-full flex items-center gap-4 px-5 py-4 rounded-xl font-bold transition-all ${currentPath === '/routines' ? 'bg-violet-600 text-white shadow-xl' : 'text-slate-500 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800'}`}><ListChecks size={20} /> Routines</button>
             <button onClick={() => navigateTo('/milestones')} className={`w-full flex items-center gap-4 px-5 py-4 rounded-xl font-bold transition-all ${currentPath === '/milestones' ? 'bg-violet-600 text-white shadow-xl' : 'text-slate-500 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800'}`}><Target size={20} /> Milestones</button>
             <button onClick={() => navigateTo('/insights')} className={`w-full flex items-center gap-4 px-5 py-4 rounded-xl font-bold transition-all ${currentPath === '/insights' ? 'bg-violet-600 text-white shadow-xl' : 'text-slate-500 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800'}`}><BarChart3 size={20} /> Insights</button>
             <button onClick={() => navigateTo('/trophies')} className={`w-full flex items-center gap-4 px-5 py-4 rounded-xl font-bold transition-all ${currentPath === '/trophies' ? 'bg-violet-600 text-white shadow-xl' : 'text-slate-500 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800'}`}><Medal size={20} /> Trophies</button>
          </nav>
          <button onClick={handleSignOut} className="flex items-center gap-4 px-5 py-3 text-slate-400 hover:text-rose-600 transition-colors text-sm font-bold w-full mt-auto"><LogOut size={18} /> Sign Out</button>
        </div>
      </aside>

      <div className="flex-1 flex flex-col h-full overflow-hidden">
        <header className="h-20 flex items-center justify-between px-8 bg-white/50 dark:bg-slate-900/50 backdrop-blur-md border-b border-slate-200 dark:border-slate-800 shrink-0">
            <button onClick={() => setSidebarOpen(true)} className="lg:hidden p-2 text-slate-600 dark:text-white"><Menu /></button>
            <div className="flex items-center gap-6 ml-auto">
                <div className="hidden sm:flex items-center gap-2">
                    {saveStatus === 'saving' ? (
                        <div className="flex items-center gap-2 text-violet-500 animate-pulse">
                            <Cloud size={16} /> <span className="text-[10px] font-black uppercase tracking-widest">Syncing</span>
                        </div>
                    ) : (
                        <div className="flex items-center gap-2 text-slate-400">
                            <CheckCircle2 size={16} /> <span className="text-[10px] font-black uppercase tracking-widest">Saved</span>
                        </div>
                    )}
                </div>
                <button onClick={() => setIsDarkMode(!isDarkMode)} className="p-2.5 bg-white dark:bg-slate-800 rounded-xl border border-slate-200 dark:border-slate-700 shadow-sm transition-transform">{isDarkMode ? <Sun size={18} /> : <Moon size={18} />}</button>
                <div className="flex items-center gap-3 pl-4 border-l border-slate-200 dark:border-slate-700">
                    <span className="hidden sm:inline font-bold text-sm text-slate-700 dark:text-slate-200">{user.name}</span>
                    <div className="w-10 h-10 bg-violet-600 rounded-xl flex items-center justify-center text-white font-black">{user.name[0]}</div>
                </div>
            </div>
        </header>

        <main className="flex-1 overflow-y-auto p-8 lg:p-12 blueprint-grid relative">
            <div className="max-w-6xl mx-auto pb-24">
                {renderContent()}
            </div>
        </main>
      </div>

      <Suspense fallback={null}><KairoChat habits={state.habits} goals={state.goals} logs={state.logs} /></Suspense>

      {/* Habit Modal */}
      <Modal isOpen={isHabitModalOpen} onClose={() => setHabitModalOpen(false)} title="New Routine">
          <div className="space-y-8">
              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-400 dark:text-slate-500 ml-1">Routine Label</label>
                <input value={newHabitTitle} onChange={e => setNewHabitTitle(e.target.value)} placeholder="e.g. Morning Meditation" className="w-full bg-slate-50 dark:bg-slate-800/50 p-5 rounded-2xl font-bold border-2 border-slate-100 dark:border-slate-700 focus:border-violet-600 outline-none text-slate-900 dark:text-white" autoFocus />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-400 dark:text-slate-500 ml-1">Frequency Cycle</label>
                <div className="flex bg-slate-100 dark:bg-slate-800 p-1 rounded-2xl border border-slate-200 dark:border-slate-700">
                  {frequencies.filter(f => f.type !== Frequency.ONCE).map((freq) => (
                    <button key={freq.type} onClick={() => setNewHabitFrequency(freq.type)} className={`flex-1 py-3 text-xs font-black rounded-xl transition-all ${newHabitFrequency === freq.type ? 'bg-white dark:bg-slate-700 text-violet-600 dark:text-violet-400 shadow-sm' : 'text-slate-500 hover:text-slate-700 dark:text-slate-400'}`}>
                      {freq.label.toUpperCase()}
                    </button>
                  ))}
                </div>
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-400 dark:text-slate-500 ml-1">Category</label>
                <div className="grid grid-cols-5 gap-2">
                  {categories.map((cat) => {
                    const Icon = cat.icon;
                    return (
                      <button key={cat.type} onClick={() => setNewHabitCategory(cat.type)} className={`flex flex-col items-center justify-center p-3 rounded-2xl border-2 transition-all gap-2 ${newHabitCategory === cat.type ? 'bg-violet-600 border-violet-600 text-white shadow-lg' : 'bg-white dark:bg-slate-800 border-slate-100 dark:border-slate-700 text-slate-500 dark:text-slate-400 hover:border-violet-300'}`}>
                        <Icon size={20} />
                      </button>
                    );
                  })}
                </div>
              </div>
              <button onClick={addHabit} disabled={!newHabitTitle.trim()} className="w-full bg-violet-600 disabled:bg-slate-300 text-white py-5 rounded-2xl font-black shadow-xl hover:bg-violet-700 transition-all flex items-center justify-center gap-3">
                <Plus size={24} strokeWidth={3} /> ESTABLISH ROUTINE
              </button>
          </div>
      </Modal>

      {/* Goal Modal */}
      <Modal isOpen={isGoalModalOpen} onClose={() => setGoalModalOpen(false)} title="New Milestone">
          <div className="space-y-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-400 ml-1">Milestone Name</label>
                <input value={newGoalTitle} onChange={e => setNewGoalTitle(e.target.value)} placeholder="e.g. Read 500 Pages" className="w-full bg-slate-50 dark:bg-slate-800/50 p-5 rounded-2xl font-bold border-2 border-slate-100 dark:border-slate-700 focus:border-emerald-600 outline-none text-slate-900 dark:text-white" />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-400 ml-1">Target</label>
                    <input type="number" value={newGoalTarget} onChange={e => setNewGoalTarget(parseInt(e.target.value) || 0)} className="w-full bg-slate-50 dark:bg-slate-800/50 p-5 rounded-2xl font-bold border-2 border-slate-100 dark:border-slate-700 focus:border-emerald-600 outline-none text-slate-900 dark:text-white" />
                </div>
                <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-400 ml-1">Unit</label>
                    <input value={newGoalUnit} onChange={e => setNewGoalUnit(e.target.value)} placeholder="e.g. Pages" className="w-full bg-slate-50 dark:bg-slate-800/50 p-5 rounded-2xl font-bold border-2 border-slate-100 dark:border-slate-700 focus:border-emerald-600 outline-none text-slate-900 dark:text-white" />
                </div>
              </div>
              <button onClick={addGoal} disabled={!newGoalTitle.trim()} className="w-full bg-emerald-600 disabled:bg-slate-300 text-white py-5 rounded-2xl font-black shadow-xl hover:bg-emerald-700 transition-all flex items-center justify-center gap-3">
                <Trophy size={20} /> SET MILESTONE
              </button>
          </div>
      </Modal>
    </div>
  );
}

import React, { useState, useEffect, Suspense, lazy, useCallback, useMemo } from 'react';
import { 
  Plus, Layout, CheckCircle2, Target, Menu, Home, ListChecks, 
  LogOut, Moon, Sun, Cloud, BarChart3, Medal, Sparkles,
  Heart, Briefcase, GraduationCap, Compass, HelpCircle, 
  Trophy, Repeat, Calendar, Flag
} from 'lucide-react';
import { format } from 'date-fns';
import { supabase, isSupabaseConfigured } from './services/supabaseClient';

import { Habit, Goal, Category, AppState, Frequency, User, DailyLog } from './types';
import { AuthScreen, TEST_ACCOUNT_ID } from './components/AuthScreen';
import { LandingPage } from './components/LandingPage';
import { HabitTracker } from './components/HabitTracker';
import { GoalTracker } from './components/GoalTracker';
import { AIOverview } from './components/AIOverview';
import { Modal } from './components/UIComponents';

// Lazy loaded modules for performance
const Analytics = lazy(() => import('./components/Analytics').then(m => ({ default: m.Analytics })));
const Achievements = lazy(() => import('./components/Achievements').then(m => ({ default: m.Achievements })));
const KairoChat = lazy(() => import('./components/KairoChat').then(m => ({ default: m.KairoChat })));

const getTodayKey = () => format(new Date(), 'yyyy-MM-dd');

export default function App() {
  const [user, setUser] = useState<User | null>(null);
  const [state, setState] = useState<AppState>({ habits: [], goals: [], logs: {}, earnedBadges: [] });
  const [isLoaded, setIsLoaded] = useState(false);
  const [saveStatus, setSaveStatus] = useState<'saved' | 'saving' | 'error'>('saved');
  const [currentPath, setCurrentPath] = useState(window.location.pathname || '/');

  // Sidebar and Modal State
  const [isSidebarOpen, setSidebarOpen] = useState(false); 
  const [isHabitModalOpen, setHabitModalOpen] = useState(false);
  const [isGoalModalOpen, setGoalModalOpen] = useState(false);

  // Form State
  const [newHabitTitle, setNewHabitTitle] = useState('');
  const [newHabitCategory, setNewHabitCategory] = useState<Category>(Category.OTHER);
  const [newHabitFrequency, setNewHabitFrequency] = useState<Frequency>(Frequency.DAILY);
  const [newGoalTitle, setNewGoalTitle] = useState('');
  const [newGoalTarget, setNewGoalTarget] = useState<number>(10);
  const [newGoalUnit, setNewGoalUnit] = useState('Units');
  const [newGoalFrequency, setNewGoalFrequency] = useState<Frequency>(Frequency.ONCE);

  const [isDarkMode, setIsDarkMode] = useState(() => {
    if (typeof window !== 'undefined') {
      return localStorage.getItem('theme') === 'dark' || 
             (!localStorage.getItem('theme') && window.matchMedia('(prefers-color-scheme: dark)').matches);
    }
    return false;
  });

  const navigateTo = (path: string) => {
    window.history.pushState({}, '', path);
    setCurrentPath(path);
    setSidebarOpen(false);
  };

  const loadUserData = useCallback(async (userData: User) => {
    const client = supabase; if (!client) { setIsLoaded(true); return; }
    try {
      const { data, error } = await client.from('user_data').select('content').eq('user_id', userData.id).single();
      if (data?.content) setState(data.content as AppState);
    } catch (err) {
        console.warn("Starting fresh record for architect:", userData.email);
    } finally { setIsLoaded(true); }
  }, []);

  // Sync theme
  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('theme', 'light');
    }
  }, [isDarkMode]);

  // Combined Auth Effect
  useEffect(() => {
    const client = supabase;
    if (!isSupabaseConfigured() || !client) { setIsLoaded(true); return; }

    client.auth.getSession().then(({ data: { session } }) => {
        if (session?.user) {
            const userData: User = {
                id: session.user.id,
                email: session.user.email || '',
                name: session.user.user_metadata?.full_name || 'Architect'
            };
            setUser(userData);
            loadUserData(userData);
            if (window.location.pathname === '/' || window.location.pathname === '/login') navigateTo('/dashboard');
        } else {
            setIsLoaded(true);
        }
    });

    const { data: { subscription } } = client.auth.onAuthStateChange((event, session) => {
        if (event === 'SIGNED_IN' && session?.user) {
            const userData: User = {
                id: session.user.id,
                email: session.user.email || '',
                name: session.user.user_metadata?.full_name || 'Architect'
            };
            setUser(userData);
            loadUserData(userData);
            navigateTo('/dashboard');
        } else if (event === 'SIGNED_OUT') {
            setUser(null);
            setState({ habits: [], goals: [], logs: {}, earnedBadges: [] });
            navigateTo('/');
        }
    });

    return () => subscription.unsubscribe();
  }, [loadUserData]);

  // Achievement Engine - Auto-check and award badges
  useEffect(() => {
    if (!isLoaded || !user) return;

    const todayKey = getTodayKey();
    const todayLog = (state.logs[todayKey] || { completedHabitIds: [] }) as DailyLog;
    const totalCompletions = (Object.values(state.logs) as DailyLog[]).reduce((acc, log) => acc + log.completedHabitIds.length, 0);
    const hasActiveHabits = state.habits.length > 0;
    const maxStreak = Math.max(0, ...state.habits.map(h => h.streak));
    const hasCompletedGoal = state.goals.some(g => g.current >= g.target);

    const newBadges: string[] = [];
    if (hasActiveHabits) newBadges.push('first_step');
    if (state.habits.length >= 5) newBadges.push('architect');
    if (hasCompletedGoal) newBadges.push('goal_getter');
    if (maxStreak >= 3) newBadges.push('streak_3');
    if (maxStreak >= 7) newBadges.push('streak_7');
    if (maxStreak >= 30) newBadges.push('streak_30');
    if (totalCompletions >= 50) newBadges.push('consistent');
    if (hasActiveHabits && todayLog.completedHabitIds.length === state.habits.length) newBadges.push('high_flyer');

    const updatedBadges = [...new Set([...state.earnedBadges, ...newBadges])];

    if (updatedBadges.length !== state.earnedBadges.length) {
      setState(prev => ({ ...prev, earnedBadges: updatedBadges }));
    }
  }, [state.habits, state.goals, state.logs, isLoaded, user]);

  // Auto-Save
  useEffect(() => {
    if (!isLoaded || !user || user.id === TEST_ACCOUNT_ID) return;

    const saveData = async () => {
      setSaveStatus('saving');
      const client = supabase; if (!client) return;
      try {
        const { error } = await client.from('user_data').upsert({ 
            user_id: user.id, 
            content: state, 
            updated_at: new Date().toISOString() 
        }, { onConflict: 'user_id' });

        if (error) throw error;
        setSaveStatus('saved');
      } catch (err) { 
        console.error("Cloud Sync Error:", err);
        setSaveStatus('error'); 
      }
    };
    const timeoutId = setTimeout(saveData, 3000);
    return () => clearTimeout(timeoutId);
  }, [state, isLoaded, user]);

  const handleSignOut = async () => {
    if (user?.id === TEST_ACCOUNT_ID) {
      setUser(null);
      setState({ habits: [], goals: [], logs: {}, earnedBadges: [] });
      navigateTo('/');
    } else {
      await supabase?.auth.signOut();
    }
  };

  const toggleHabit = (id: string) => {
    const todayKey = getTodayKey();
    setState(prev => {
      const currentLog = prev.logs[todayKey] || { date: todayKey, completedHabitIds: [], goalProgress: {} };
      const isCompleted = currentLog.completedHabitIds.includes(id);
      const newCompletedIds = isCompleted 
        ? currentLog.completedHabitIds.filter(hid => hid !== id)
        : [...currentLog.completedHabitIds, id];

      if (!isCompleted && typeof window !== 'undefined' && (window as any).confetti) {
        (window as any).confetti({
          particleCount: 100,
          spread: 70,
          origin: { y: 0.6 },
          colors: ['#7c3aed', '#10b981', '#6366f1']
        });
      }

      // Update streaks logic
      const updatedHabits = prev.habits.map(h => {
        if (h.id === id) {
          return { ...h, streak: !isCompleted ? h.streak + 1 : Math.max(0, h.streak - 1) };
        }
        return h;
      });

      return {
        ...prev,
        habits: updatedHabits,
        logs: { 
          ...prev.logs, 
          [todayKey]: { ...currentLog, completedHabitIds: newCompletedIds } 
        }
      };
    });
  };

  const addHabit = () => {
    if (!newHabitTitle.trim()) return;
    const habitId = typeof crypto !== 'undefined' && crypto.randomUUID ? crypto.randomUUID() : Math.random().toString(36).substring(2, 15);
    const newHabit: Habit = { 
      id: habitId,
      title: newHabitTitle, 
      category: newHabitCategory, 
      createdAt: new Date().toISOString(), 
      streak: 0, 
      frequency: newHabitFrequency 
    };
    setState(prev => ({ ...prev, habits: [...prev.habits, newHabit] }));
    setNewHabitTitle(''); 
    setHabitModalOpen(false);
  };

  const addGoal = () => {
    if (!newGoalTitle.trim()) return;
    const goalId = typeof crypto !== 'undefined' && crypto.randomUUID ? crypto.randomUUID() : Math.random().toString(36).substring(2, 15);
    const newGoal: Goal = {
      id: goalId,
      title: newGoalTitle,
      target: newGoalTarget,
      current: 0,
      unit: newGoalUnit,
      frequency: newGoalFrequency
    };
    setState(prev => ({ ...prev, goals: [...prev.goals, newGoal] }));
    setNewGoalTitle('');
    setGoalModalOpen(false);
  };

  const renderContent = () => {
    const todayKey = getTodayKey();
    const todayLog = state.logs[todayKey] || { date: todayKey, completedHabitIds: [], goalProgress: {} };
    const percentage = state.habits.length > 0 ? Math.round((todayLog.completedHabitIds.length / state.habits.length) * 100) : 0;

    switch(currentPath) {
      case '/routines':
        return (
          <div className="space-y-8 animate-in fade-in duration-500">
            <div className="flex justify-between items-center mb-4">
                <h2 className="text-3xl font-black text-slate-900 dark:text-white uppercase tracking-tighter">Your Routines</h2>
                <button onClick={() => setHabitModalOpen(true)} className="bg-violet-600 text-white px-6 py-3 rounded-xl font-bold flex items-center gap-2 shadow-lg shadow-violet-200 dark:shadow-none"><Plus size={20}/> New</button>
            </div>
            <HabitTracker habits={state.habits} completedHabitIds={todayLog.completedHabitIds} onToggleHabit={toggleHabit} onDeleteHabit={(id) => setState(prev => ({ ...prev, habits: prev.habits.filter(h => h.id !== id) }))} />
          </div>
        );
      case '/milestones':
        return (
          <div className="space-y-8 animate-in fade-in duration-500">
            <div className="flex justify-between items-center mb-4">
