import { User } from '../types';

interface AuthScreenProps {
  onAuthSuccess: (user: User) => void;
}

export const TEST_ACCOUNT_ID = '77777777-7777-7777-7777-777777777777';

export const AuthScreen: React.FC<AuthScreenProps> = ({ onAuthSuccess }) => {
  const [mode, setMode] = useState<'login' | 'signup'>('login');

  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const isTestAccount = email.toLowerCase().trim() === 'test@test.com';

  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError(null);

    // Test Mode bypass
    if (isTestAccount) {
        setTimeout(() => {
            onAuthSuccess({
                id: TEST_ACCOUNT_ID,
                email: 'test@test.com',
                name: 'Test Architect'
            });
            setLoading(false);
        }, 600);
        return;
    }

    if (!isSupabaseConfigured() || !supabase) {
        setError("Database connection missing. Please configure Supabase.");
        setLoading(false);
        return;
    }

    try {
      if (mode === 'signup') {
        const { data, error: signupError } = await supabase.auth.signUp({
          email,
          password,
          options: {
            data: { full_name: name },
          },
        });
        if (signupError) throw signupError;

        if (data?.user) {
            onAuthSuccess({
                id: data.user.id,
                email: data.user.email || '',
                name: data.user.user_metadata?.full_name || name || 'Architect'
            });
        }
      } else {
        const { data, error: loginError } = await supabase.auth.signInWithPassword({
          email,
          password,
        });
        if (loginError) throw loginError;

        if (data?.user) {
            onAuthSuccess({
                id: data.user.id,
                email: data.user.email || '',
                name: data.user.user_metadata?.full_name || 'Architect'
            });
        }
      }
    } catch (err: any) {
      console.error("Auth error:", err);
      if (err.message === "Invalid login credentials") {
          setError("Incorrect email or password. Please try again.");
      } else if (err.message.includes("rate limit")) {
          setError("Too many attempts. Please wait a moment and try again.");
      } else {
          setError(err.message || "Authentication failed.");
      }
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-slate-50 dark:bg-slate-950 p-6 font-sans transition-colors duration-300">
      <div className="bg-white dark:bg-slate-900 w-full max-w-md p-10 rounded-[2.5rem] shadow-2xl border border-slate-200 dark:border-slate-800">
        <div className="text-center mb-10">
          <div className="inline-flex items-center justify-center w-16 h-16 bg-violet-600 rounded-2xl shadow-xl mb-6">
            <Layout className="text-white" size={32} />
          </div>
          <h1 className="text-3xl font-black text-slate-900 dark:text-white uppercase tracking-tighter">Habit<span className="text-violet-600">Architect</span></h1>
          <p className="text-slate-500 dark:text-slate-400 font-bold uppercase tracking-widest text-[10px] mt-2">Professional System Tracking</p>
        </div>

        {error && (
          <div className="mb-6 p-4 bg-rose-50 dark:bg-rose-900/20 border border-rose-100 dark:border-rose-800 rounded-2xl text-rose-700 dark:text-rose-400 text-sm font-bold flex items-center gap-3">
            <AlertCircle size={18} className="shrink-0" /> {error}
          </div>
        )}

        <div className="flex bg-slate-100 dark:bg-slate-800 p-1 rounded-2xl border border-slate-200 dark:border-slate-700 mb-8">
            <button 
                type="button" 
                onClick={() => { setMode('login'); setError(null); }} 
                className={`flex-1 py-3 text-xs font-black rounded-xl transition-all ${mode === 'login' ? 'bg-white dark:bg-slate-700 text-violet-600 dark:text-violet-400 shadow-sm' : 'text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-200'}`}
            >
                LOG IN
            </button>
            <button 
                type="button" 
                onClick={() => { setMode('signup'); setError(null); }} 
                className={`flex-1 py-3 text-xs font-black rounded-xl transition-all ${mode === 'signup' ? 'bg-white dark:bg-slate-700 text-violet-600 dark:text-violet-400 shadow-sm' : 'text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-200'}`}
            >
                SIGN UP
            </button>
        </div>

        <form onSubmit={handleAuth} className="space-y-5">
            {mode === 'signup' && (
                <div className="space-y-1">
                    <label className="text-[10px] font-black uppercase tracking-widest text-slate-400 dark:text-slate-500 ml-1">Full Name</label>
                    <div className="relative">
                        <UserIcon className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-400 dark:text-slate-500" size={18} />
                        <input 
                            type="text" 
                            required 
                            value={name} 
                            onChange={e => setName(e.target.value)} 
                            className="w-full pl-14 pr-6 py-4 bg-slate-50 dark:bg-slate-800/50 border border-slate-200 dark:border-slate-700 rounded-2xl outline-none focus:border-violet-600 focus:ring-4 focus:ring-violet-50 dark:focus:ring-violet-900/20 font-bold transition-all text-slate-900 dark:text-white" 
                            placeholder="Alex Architect" 
                        />
                    </div>
                </div>
            )}

            <div className="space-y-1">
                <label className="text-[10px] font-black uppercase tracking-widest text-slate-400 dark:text-slate-500 ml-1">Email Address</label>
                <div className="relative">
                    <Mail className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-400 dark:text-slate-500" size={18} />
                    <input 
                        type="email" 
                        required 
                        value={email} 
                        onChange={e => setEmail(e.target.value)} 
                        className="w-full pl-14 pr-6 py-4 bg-slate-50 dark:bg-slate-800/50 border border-slate-200 dark:border-slate-700 rounded-2xl outline-none focus:border-violet-600 focus:ring-4 focus:ring-violet-50 dark:focus:ring-violet-900/20 font-bold transition-all text-slate-900 dark:text-white" 
                        placeholder="email@example.com" 
                    />
                </div>
            </div>

            <div className="space-y-1">
                <label className="text-[10px] font-black uppercase tracking-widest text-slate-400 dark:text-slate-500 ml-1">Secure Password</label>
                <div className="relative">
                    <Lock className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-400 dark:text-slate-500" size={18} />
                    <input 
                        type={showPassword ? "text" : "password"} 
                        required 
                        value={password} 
                        onChange={e => setPassword(e.target.value)} 
                        className="w-full pl-14 pr-14 py-4 bg-slate-50 dark:bg-slate-800/50 border border-slate-200 dark:border-slate-700 rounded-2xl outline-none focus:border-violet-600 focus:ring-4 focus:ring-violet-50 dark:focus:ring-violet-900/20 font-bold transition-all text-slate-900 dark:text-white" 
                        placeholder="••••••••" 
                    />
                    <button 
                        type="button" 
                        onClick={() => setShowPassword(!showPassword)}
                        className="absolute right-5 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-600 dark:hover:text-slate-300"
                    >
                        {showPassword ? <EyeOff size={18} /> : <Eye size={18} />}
                    </button>
                </div>
            </div>

            <button 
                type="submit" 
                disabled={loading} 
                className="w-full py-5 bg-slate-900 dark:bg-white text-white dark:text-slate-900 rounded-2xl font-black shadow-xl hover:bg-slate-800 dark:hover:bg-slate-100 active:scale-95 transition-all flex items-center justify-center gap-3 mt-4"
            >
                {loading ? <Loader2 className="animate-spin" /> : (
                    <>
                        {mode === 'signup' ? 'ESTABLISH ACCOUNT' : 'SECURE ACCESS'} 
                        <ArrowRight size={20} />
                    </>
                )}
            </button>

            {isTestAccount && (
                <div className="mt-6 p-4 bg-violet-50 dark:bg-violet-900/20 border border-violet-100 dark:border-violet-800 rounded-2xl text-center">
                    <p className="text-violet-600 dark:text-violet-400 font-black text-[10px] uppercase tracking-widest animate-pulse">Test Architect Entry</p>
                    <p className="text-violet-500 dark:text-violet-500 font-bold text-[9px] mt-1">Use any password to enter the demo vault</p>
                </div>
            )}
        </form>

        <p className="text-center mt-8 text-slate-400 dark:text-slate-600 font-bold text-[10px] uppercase tracking-[0.2em]">
            Behavioral Integrity Protocol Enabled
        </p>
      </div>
    </div>
  );
};

import React, { useState, useEffect, Suspense, lazy, useCallback, useMemo } from 'react';
import { 
  Plus, Layout, CheckCircle2, Target, Menu, Home, ListChecks, 
  LogOut, Moon, Sun, Cloud, BarChart3, Medal, Sparkles,
  Heart, Briefcase, GraduationCap, Compass, HelpCircle, 
  Trophy, Repeat, Calendar, Flag
} from 'lucide-react';
import { format, subDays } from 'date-fns';
import { supabase, isSupabaseConfigured } from './services/supabaseClient';

import { Habit, Goal, Category, AppState, Frequency, User, DailyLog } from './types';
import { AuthScreen, TEST_ACCOUNT_ID } from './components/AuthScreen';
import { LandingPage } from './components/LandingPage';
import { HabitTracker } from './components/HabitTracker';
import { GoalTracker } from './components/GoalTracker';
import { AIOverview } from './components/AIOverview';
import { Modal } from './components/UIComponents';

// Lazy loaded modules for performance
const Analytics = lazy(() => import('./components/Analytics').then(m => ({ default: m.Analytics })));
const Achievements = lazy(() => import('./components/Achievements').then(m => ({ default: m.Achievements })));
const KairoChat = lazy(() => import('./components/KairoChat').then(m => ({ default: m.KairoChat })));

const getTodayKey = () => format(new Date(), 'yyyy-MM-dd');

export default function App() {
  const [user, setUser] = useState<User | null>(null);
  const [state, setState] = useState<AppState>({ habits: [], goals: [], logs: {}, earnedBadges: [] });
  const [isLoaded, setIsLoaded] = useState(false);
  const [saveStatus, setSaveStatus] = useState<'saved' | 'saving' | 'error'>('saved');
  const [currentPath, setCurrentPath] = useState(window.location.pathname || '/');

  // Sidebar and Modal State
  const [isSidebarOpen, setSidebarOpen] = useState(false); 
  const [isHabitModalOpen, setHabitModalOpen] = useState(false);
  const [isGoalModalOpen, setGoalModalOpen] = useState(false);

  // Form State
  const [newHabitTitle, setNewHabitTitle] = useState('');
  const [newHabitCategory, setNewHabitCategory] = useState<Category>(Category.OTHER);
  const [newHabitFrequency, setNewHabitFrequency] = useState<Frequency>(Frequency.DAILY);
  const [newGoalTitle, setNewGoalTitle] = useState('');
  const [newGoalTarget, setNewGoalTarget] = useState<number>(10);
  const [newGoalUnit, setNewGoalUnit] = useState('Units');
  const [newGoalFrequency, setNewGoalFrequency] = useState<Frequency>(Frequency.ONCE);

  const [isDarkMode, setIsDarkMode] = useState(() => {
    if (typeof window !== 'undefined') {
      return localStorage.getItem('theme') === 'dark' || 
             (!localStorage.getItem('theme') && window.matchMedia('(prefers-color-scheme: dark)').matches);
    }
    return false;
  });

  const navigateTo = (path: string) => {
    window.history.pushState({}, '', path);
    setCurrentPath(path);
    setSidebarOpen(false);
  };

  const loadUserData = useCallback(async (userData: User) => {
    const client = supabase; if (!client) { setIsLoaded(true); return; }
    try {
      const { data, error } = await client.from('user_data').select('content').eq('user_id', userData.id).single();
      if (data?.content) setState(data.content as AppState);
    } catch (err) {
        console.warn("Starting fresh record for architect:", userData.email);
    } finally { setIsLoaded(true); }
  }, []);

  // Sync theme
  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('theme', 'light');
    }
  }, [isDarkMode]);

  // Combined Auth Effect
  useEffect(() => {
    const client = supabase;
    if (!isSupabaseConfigured() || !client) { setIsLoaded(true); return; }

    client.auth.getSession().then(({ data: { session } }) => {
        if (session?.user) {
            const userData: User = {
                id: session.user.id,
                email: session.user.email || '',
                name: session.user.user_metadata?.full_name || 'Architect'
            };
            setUser(userData);
            loadUserData(userData);
            if (window.location.pathname === '/' || window.location.pathname === '/login') navigateTo('/dashboard');
        } else {
            setIsLoaded(true);
        }
    });

    const { data: { subscription } } = client.auth.onAuthStateChange((event, session) => {
        if (event === 'SIGNED_IN' && session?.user) {
            const userData: User = {
                id: session.user.id,
                email: session.user.email || '',
                name: session.user.user_metadata?.full_name || 'Architect'
            };
            setUser(userData);
            loadUserData(userData);
            navigateTo('/dashboard');
        } else if (event === 'SIGNED_OUT') {
            setUser(null);
            setState({ habits: [], goals: [], logs: {}, earnedBadges: [] });
            navigateTo('/');
        }
    });

    return () => subscription.unsubscribe();
  }, [loadUserData]);

  // Achievement Engine - Auto-check and award badges
  useEffect(() => {
    if (!isLoaded || !user) return;

    const todayKey = getTodayKey();
    const todayLog = (state.logs[todayKey] || { completedHabitIds: [] }) as DailyLog;
    const totalCompletions = (Object.values(state.logs) as DailyLog[]).reduce((acc, log) => acc + log.completedHabitIds.length, 0);
    const hasActiveHabits = state.habits.length > 0;
    const maxStreak = Math.max(0, ...state.habits.map(h => h.streak));
    const hasCompletedGoal = state.goals.some(g => g.current >= g.target);

    const newBadges: string[] = [];
    if (hasActiveHabits) newBadges.push('first_step');
    if (state.habits.length >= 5) newBadges.push('architect');
    if (hasCompletedGoal) newBadges.push('goal_getter');
    if (maxStreak >= 3) newBadges.push('streak_3');
    if (maxStreak >= 7) newBadges.push('streak_7');
    if (maxStreak >= 30) newBadges.push('streak_30');
    if (totalCompletions >= 50) newBadges.push('consistent');
    if (hasActiveHabits && todayLog.completedHabitIds.length === state.habits.length) newBadges.push('high_flyer');

    const updatedBadges = [...new Set([...state.earnedBadges, ...newBadges])];

    if (updatedBadges.length !== state.earnedBadges.length) {
      setState(prev => ({ ...prev, earnedBadges: updatedBadges }));
    }
  }, [state.habits, state.goals, state.logs, isLoaded, user]);

  // Auto-Save
  useEffect(() => {
    if (!isLoaded || !user || user.id === TEST_ACCOUNT_ID) return;

    const saveData = async () => {
      setSaveStatus('saving');
      const client = supabase; if (!client) return;
      try {
        const { error } = await client.from('user_data').upsert({ 
            user_id: user.id, 
            content: state, 
            updated_at: new Date().toISOString() 
        }, { onConflict: 'user_id' });

        if (error) throw error;
        setSaveStatus('saved');
      } catch (err) { 
        console.error("Cloud Sync Error:", err);
        setSaveStatus('error'); 
      }
    };
    const timeoutId = setTimeout(saveData, 3000);
    return () => clearTimeout(timeoutId);
  }, [state, isLoaded, user]);

  const handleSignOut = async () => {
    if (user?.id === TEST_ACCOUNT_ID) {
      setUser(null);
      setState({ habits: [], goals: [], logs: {}, earnedBadges: [] });
      navigateTo('/');
    } else {
      await supabase?.auth.signOut();
    }
  };

  const handleStartDemo = () => {
    // Populate demo data
    const demoHabits: Habit[] = [
        { id: 'h1', title: 'Deep Work Session', category: Category.WORK, streak: 12, frequency: Frequency.DAILY, createdAt: subDays(new Date(), 30).toISOString() },
        { id: 'h2', title: '5km Run', category: Category.HEALTH, streak: 5, frequency: Frequency.DAILY, createdAt: subDays(new Date(), 20).toISOString() },
        { id: 'h3', title: 'Meditation', category: Category.MINDFULNESS, streak: 21, frequency: Frequency.DAILY, createdAt: subDays(new Date(), 40).toISOString() },
        { id: 'h4', title: 'Skill Study', category: Category.LEARNING, streak: 3, frequency: Frequency.DAILY, createdAt: subDays(new Date(), 10).toISOString() },
    ];

    const demoGoals: Goal[] = [
        { id: 'g1', title: 'Read "Atomic Habits"', target: 320, current: 245, unit: 'Pages', frequency: Frequency.ONCE },
        { id: 'g2', title: 'Launch Side Project', target: 10, current: 7, unit: 'Modules', frequency: Frequency.ONCE }
    ];

    const todayKey = getTodayKey();
    const demoLogs: Record<string, DailyLog> = {
        [todayKey]: { date: todayKey, completedHabitIds: ['h1', 'h3'], goalProgress: {} },
        [format(subDays(new Date(), 1), 'yyyy-MM-dd')]: { date: todayKey, completedHabitIds: ['h1', 'h2', 'h3', 'h4'], goalProgress: {} },
        [format(subDays(new Date(), 2), 'yyyy-MM-dd')]: { date: todayKey, completedHabitIds: ['h1', 'h3'], goalProgress: {} }
    };

    setState({
        habits: demoHabits,
        goals: demoGoals,
        logs: demoLogs,
        earnedBadges: ['first_step', 'streak_3', 'streak_7', 'architect']
    });

    setUser({
        id: TEST_ACCOUNT_ID,
        email: 'demo@habitarch.com',
        name: 'Demo Architect'
    });

    navigateTo('/dashboard');
  };

  const toggleHabit = (id: string) => {
    const todayKey = getTodayKey();
    setState(prev => {
      const currentLog = prev.logs[todayKey] || { date: todayKey, completedHabitIds: [], goalProgress: {} };
      const isCompleted = currentLog.completedHabitIds.includes(id);
      const newCompletedIds = isCompleted 
        ? currentLog.completedHabitIds.filter(hid => hid !== id)
        : [...currentLog.completedHabitIds, id];

      if (!isCompleted && typeof window !== 'undefined' && (window as any).confetti) {
        (window as any).confetti({
          particleCount: 100,
          spread: 70,
          origin: { y: 0.6 },
          colors: ['#7c3aed', '#10b981', '#6366f1']
        });
      }

      // Update streaks logic
      const updatedHabits = prev.habits.map(h => {
        if (h.id === id) {
          return { ...h, streak: !isCompleted ? h.streak + 1 : Math.max(0, h.streak - 1) };
        }
        return h;
      });

      return {
        ...prev,
        habits: updatedHabits,
        logs: { 
          ...prev.logs, 
          [todayKey]: { ...currentLog, completedHabitIds: newCompletedIds } 
        }
      };
    });
  };

  const addHabit = () => {
    if (!newHabitTitle.trim()) return;
    const habitId = typeof crypto !== 'undefined' && crypto.randomUUID ? crypto.randomUUID() : Math.random().toString(36).substring(2, 15);
    const newHabit: Habit = { 
      id: habitId,
      title: newHabitTitle, 
      category: newHabitCategory, 
      createdAt: new Date().toISOString(), 
      streak: 0, 
      frequency: newHabitFrequency 
    };
    setState(prev => ({ ...prev, habits: [...prev.habits, newHabit] }));
    setNewHabitTitle(''); 
    setHabitModalOpen(false);
  };

  const addGoal = () => {
    if (!newGoalTitle.trim()) return;
    const goalId = typeof crypto !== 'undefined' && crypto.randomUUID ? crypto.randomUUID() : Math.random().toString(36).substring(2, 15);
    const newGoal: Goal = {
      id: goalId,
      title: newGoalTitle,
      target: newGoalTarget,
      current: 0,
      unit: newGoalUnit,
      frequency: newGoalFrequency
    };
    setState(prev => ({ ...prev, goals: [...prev.goals, newGoal] }));
    setNewGoalTitle('');
    setGoalModalOpen(false);
  };

  const renderContent = () => {
    const todayKey = getTodayKey();
    const todayLog = state.logs[todayKey] || { date: todayKey, completedHabitIds: [], goalProgress: {} };
    const percentage = state.habits.length > 0 ? Math.round((todayLog.completedHabitIds.length / state.habits.length) * 100) : 0;

    switch(currentPath) {
      case '/routines':
        return (
          <div className="space-y-8 animate-in fade-in duration-500">
            <div className="flex justify-between items-center mb-4">
                <h2 className="text-3xl font-black text-slate-900 dark:text-white uppercase tracking-tighter">Your Routines</h2>
                <button onClick={() => setHabitModalOpen(true)} className="bg-violet-600 text-white px-6 py-3 rounded-xl font-bold flex items-center gap-2 shadow-lg shadow-violet-200 dark:shadow-none"><Plus size={20}/> New</button>
            </div>
            <HabitTracker habits={state.habits} completedHabitIds={todayLog.completedHabitIds} onToggleHabit={toggleHabit} onDeleteHabit={(id) => setState(prev => ({ ...prev, habits: prev.habits.filter(h => h.id !== id) }))} />
          </div>
