      </div>

      <Suspense fallback={null}><KairoChat habits={state.habits} goals={state.goals} logs={state.logs} /></Suspense>

      {/* Habit Modal */}
      <Modal isOpen={isHabitModalOpen} onClose={() => setHabitModalOpen(false)} title="New Habit">
          <div className="space-y-8">
