          {/* Stage 5: Garden / Trees */}
          {stage >= 5 && (
            <>
              <circle cx="70" cy="290" r="25" className="fill-emerald-500/20" />
              <rect x="65" y="290" width="10" height="30" className="fill-slate-400" />
