          )}

          {/* Scaffolding (Visible if today's work isn't done) */}
          {isUnderConstruction && (
            <g className="opacity-40 stroke-slate-400 stroke-1 fill-none">
              <rect x="85" y="150" width="230" height="150" />
              <line x1="85" y1="200" x2="315" y2="200" />
