        const percent = Math.floor((activeGoal.current / activeGoal.target) * 100);
        message += `🎯 *Goal Focus:* ${activeGoal.title} (${percent}%)\n`;
    }
    if (analysis) {
        const cleanAnalysis = analysis.replace(/\*\*/g, '*');
        message += `\n🤖 *Kairo's Insight:*\n${cleanAnalysis}`;
